14	export const getFromApi = async <T>({
15	  url,
16	  headers = {},
17	  successfulResponseHandler,
18	  failedResponseHandler,
19	  abortSignal,
20	  fetch = getOriginalFetch(),
21	}: {
22	  url: string;
23	  headers?: Record<string, string | undefined>;
24	  failedResponseHandler: ResponseHandler<Error>;
25	  successfulResponseHandler: ResponseHandler<T>;
26	  abortSignal?: AbortSignal;
27	  fetch?: FetchFunction;
28	}) => {
29	  try {
30	    const response = await fetch(url, {
31	      method: 'GET',
32	      headers: withUserAgentSuffix(
33	        headers,
34	        `ai-sdk/provider-utils/${VERSION}`,
35	        getRuntimeEnvironmentUserAgent(),
36	      ),
37	      signal: abortSignal,
38	    });
39	
40	    const responseHeaders = extractResponseHeaders(response);
41	
42	    if (!response.ok) {
43	      let errorInformation: {
44	        value: Error;
45	        responseHeaders?: Record<string, string> | undefined;
46	      };
47	
48	      try {
49	        errorInformation = await failedResponseHandler({
50	          response,
51	          url,
52	          requestBodyValues: {},
53	        });
54	      } catch (error) {
55	        if (isAbortError(error) || APICallError.isInstance(error)) {
56	          throw error;
57	        }
58	
59	        throw new APICallError({
60	          message: 'Failed to process error response',
61	          cause: error,
62	          statusCode: response.status,
63	          url,
64	          responseHeaders,
65	          requestBodyValues: {},
66	        });
67	      }
68	
69	      throw errorInformation.value;
70	    }
71	
72	    try {
73	      return await successfulResponseHandler({
74	        response,
75	        url,
76	        requestBodyValues: {},
77	      });
78	    } catch (error) {
79	      if (error instanceof Error) {
80	        if (isAbortError(error) || APICallError.isInstance(error)) {
81	          throw error;
