---

### Step 2 — `packages/pixelart/src/pixelart-image-settings.ts`

Defines model IDs, the style union type, and the provider-options settings interface.

```ts
export type PixelArtImageModelId =
  | 'pixelart-v1'
  | 'pixelart-pro'
  | (string & {});

export type PixelArtStyle = 'pixel' | 'retro' | '8bit';

/**
 * Provider-specific settings for PixelArt image generation.
 * Passed via `providerOptions.pixelart` in `generateImage()`.
 */
export interface PixelArtImageSettings {
  /**
   * Visual style of the generated image.
   * - `pixel`: Classic pixel art aesthetic
   * - `retro`: Retro/vintage gaming look
   * - `8bit`: 8-bit video game style
   */
  style?: PixelArtStyle;

  /**
   * Pixel density (dots per unit). Higher values produce finer detail.
   * Typical range: 4–64.
   */
  pixelDensity?: number;
}
```

---

### Step 3 — `packages/pixelart/src/pixelart-image-model.ts`

Core `ImageModelV3` implementation. Key design decisions:
- **API endpoint**: `POST https://api.pixelart.ai/v1/images/generate`
- **Response format**: Inline `b64_json` per image (no polling, no secondary download)
- **`maxImagesPerCall`**: `4`
- **Supported standard params**: `size`, `n`
- **Warnings** for unsupported params: `seed`, `aspectRatio`
- **Provider options**: `style`, `pixelDensity` → sent as `style` / `pixel_density` in the request body

```ts
import {
  ImageModelV3,
  SharedV3Warning,
} from '@ai-sdk/provider';
import {
  FetchFunction,
  InferSchema,
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers: () => Record<string, string>;
  fetch?: FetchFunction;
  _internal?: { currentDate?: () => Date };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider() { return this.config.provider; }

  constructor(
    readonly modelId: string,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt, n, size, aspectRatio, seed,
    providerOptions, headers, abortSignal,
  }: Parameters<ImageModelV3['doGenerate']>[0]):
    Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {

    const warnings: Array<SharedV3Warning> = [];

    if (seed != null) {
      warnings.push({ type: 'unsupported', feature: 'seed',
        details: 'PixelArt does not support the `seed` option.' });
    }
    if (aspectRatio != null) {
      warnings.push({ type: 'unsupported', feature: 'aspectRatio',
        details: 'PixelArt does not support `aspectRatio`. Use `size` instead.' });
    }

    const pixelartOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        prompt,
        model: this.modelId,
        n: n ?? 1,
        ...(size != null ? { size } : {}),
        ...(pixelartOptions?.style != null
          ? { style: pixelartOptions.style } : {}),
        ...(pixelartOptions?.pixelDensity != null
          ? { pixel_density: pixelartOptions.pixelDensity } : {}),
      },
      abortSignal,
      fetch: this.config.fetch,
      failedResponseHandler: pixelartFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtImageResponseSchema,
      ),
    });

    // Decode base64 images to Uint8Array
    const images = response.data.map(item => {
      const binaryString = atob(item.b64_json);
      const bytes = new Uint8Array(binaryString.length);
      for (let i = 0; i < binaryString.length; i++) {
        bytes[i] = binaryString.charCodeAt(i);
      }
      return bytes;
    });

    return {
      images,
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
    };
  }
}

// Response schema
const pixelArtImageResponseSchema = lazySchema(() =>
  zodSchema(
    z.object({
      created: z.number(),
      data: z.array(
        z.object({
          b64_json: z.string(),
        }),
      ),
    }),
  ),
);

// Error schema
const pixelArtErrorSchema = z.object({
  error: z.object({
    message: z.string(),
    code: z.string().nullish(),
  }),
});

const pixelartFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelArtErrorSchema,
  errorToMessage: data => data.error.message,
});

// Provider options schema
export const pixelArtImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      style: z.enum(['pixel', 'retro', '8bit']).nullish(),
      pixelDensity: z.number().nullish(),
    }).passthrough(),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelArtImageModelOptionsSchema
>;
```

---

### Step 4 — `packages/pixelart/src/pixelart-provider.ts`

Factory function + ProviderV3 implementation. Throws `NoSuchModelError` for unsupported model types.

