import { FetchFunction } from '@ai-sdk/provider-utils';
import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';

const TEST_BASE_URL = 'https://api.example.com';
const TEST_GENERATE_URL = `${TEST_BASE_URL}/images/generate`;

const prompt = 'A knight in pixel art style';

// A small 1x1 red PNG encoded in base64
const TEST_B64 = 'iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mP8z8BQDwADhQGAWjR9awAAAABJRU5ErkJggg==';

function createBasicModel({
  headers,
  fetch,
  currentDate,
}: {
  headers?: () => Record<string, string>;
  fetch?: FetchFunction;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel('pixelart-v1', {
    provider: 'pixelart.image',
    baseURL: TEST_BASE_URL,
    headers: headers ?? (() => ({ Authorization: 'Bearer test-key' })),
    fetch,
    _internal: {
      currentDate,
    },
  });
}

const successBody = {
  created: 1234567890,
  data: [{ b64_json: TEST_B64 }],
};

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    [TEST_GENERATE_URL]: {
      response: {
        type: 'json-value',
        body: successBody,
      },
    },
  });

  describe('doGenerate', () => {
    it('should send correct base parameters to the API', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: '256x256',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        prompt,
        model: 'pixelart-v1',
        n: 1,
        size: '256x256',
      });
    });

    it('should omit size when not provided', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 2,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).toStrictEqual({
        prompt,
        model: 'pixelart-v1',
        n: 2,
      });
      expect(body).not.toHaveProperty('size');
    });

    it('should forward provider options: style and pixelDensity', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: '512x512',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelart: { style: 'retro', pixelDensity: 16 },
        },
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        prompt,
        model: 'pixelart-v1',
        n: 1,
        size: '512x512',
        style: 'retro',
        pixel_density: 16,
      });
    });

    it('should forward style without pixelDensity', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelart: { style: '8bit' },
        },
        files: undefined,
        mask: undefined,
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).toMatchObject({ style: '8bit' });
      expect(body).not.toHaveProperty('pixel_density');
    });

    it('should warn when seed is provided', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: 42,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.warnings).toContainEqual({
        type: 'unsupported',
        feature: 'seed',
        details: 'PixelArt does not support the `seed` option.',
      });
    });

    it('should warn when aspectRatio is provided', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: '16:9',
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.warnings).toContainEqual({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'PixelArt does not support the `aspectRatio` option. Use `size` instead.',
      });
    });

    it('should return decoded Uint8Array images', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.images).toHaveLength(1);
      expect(result.images[0]).toBeInstanceOf(Uint8Array);
      // The decoded bytes should match the original base64
      const expected = Uint8Array.from(
        atob(TEST_B64),
        c => c.charCodeAt(0),
      );
      expect(result.images[0]).toEqual(expected);
    });

    it('should return multiple images when n > 1', async () => {
      server.urls[TEST_GENERATE_URL].response = {
        type: 'json-value',
        body: {
          created: 1234567890,
          data: [
            { b64_json: TEST_B64 },
            { b64_json: TEST_B64 },
          ],
        },
      };

      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 2,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.images).toHaveLength(2);
      result.images.forEach(img => expect(img).toBeInstanceOf(Uint8Array));
    });

    it('should return no warnings when no unsupported params are used', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: '256x256',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: { pixelart: { style: 'pixel', pixelDensity: 8 } },
        files: undefined,
        mask: undefined,
      });

      expect(result.warnings).toHaveLength(0);
    });

    it('should include response metadata', async () => {
      const fixedDate = new Date('2024-01-15T10:00:00Z');
      const model = createBasicModel({ currentDate: () => fixedDate });

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.response.modelId).toBe('pixelart-v1');
      expect(result.response.timestamp).toEqual(fixedDate);
    });

    it('should send Authorization header', async () => {
      const model = createBasicModel({
        headers: () => ({ Authorization: 'Bearer my-secret-key' }),
      });

      await model.doGenerate({
