import { NoSuchModelError } from '@ai-sdk/provider';
import { beforeEach, describe, expect, it, vi } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';
import { createPixelArt } from './pixelart-provider';

vi.mock('./pixelart-image-model', () => ({
  PixelArtImageModel: vi.fn(),
}));

describe('createPixelArt', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  describe('image / imageModel', () => {
    it('should construct an image model with default configuration', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      const modelId = 'pixelart-v1';

      const model = provider.image(modelId);

      expect(model).toBeInstanceOf(PixelArtImageModel);
      expect(PixelArtImageModel).toHaveBeenCalledWith(
        modelId,
        expect.objectContaining({
          provider: 'pixelart.image',
          baseURL: 'https://api.pixelart.ai/v1',
        }),
      );
    });

    it('should use imageModel() as an alias for image()', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      const modelId = 'pixelart-pro';

      provider.imageModel(modelId);

      expect(PixelArtImageModel).toHaveBeenCalledWith(
        modelId,
        expect.objectContaining({
          provider: 'pixelart.image',
        }),
      );
    });

    it('should respect a custom baseURL', () => {
      const customBaseURL = 'https://custom.pixelart.ai/v2';
      const provider = createPixelArt({
        apiKey: 'test-key',
        baseURL: customBaseURL,
      });

      provider.image('pixelart-v1');

      expect(PixelArtImageModel).toHaveBeenCalledWith(
        'pixelart-v1',
        expect.objectContaining({ baseURL: customBaseURL }),
      );
    });

    it('should strip a trailing slash from baseURL', () => {
      const provider = createPixelArt({
        apiKey: 'test-key',
        baseURL: 'https://custom.pixelart.ai/v2/',
      });

      provider.image('pixelart-v1');

      expect(PixelArtImageModel).toHaveBeenCalledWith(
        'pixelart-v1',
        expect.objectContaining({
          baseURL: 'https://custom.pixelart.ai/v2',
        }),
      );
    });

    it('should forward custom headers via the headers function', () => {
      const customHeaders = { 'X-Custom-Header': 'hello' };
      const provider = createPixelArt({
        apiKey: 'test-key',
        headers: customHeaders,
      });

      provider.image('pixelart-v1');

      expect(PixelArtImageModel).toHaveBeenCalledWith(
        'pixelart-v1',
        expect.objectContaining({ headers: expect.any(Function) }),
      );
    });

    it('should forward a custom fetch implementation', () => {
      const mockFetch = vi.fn();
      const provider = createPixelArt({
        apiKey: 'test-key',
        fetch: mockFetch,
      });

      provider.image('pixelart-v1');

      expect(PixelArtImageModel).toHaveBeenCalledWith(
        'pixelart-v1',
        expect.objectContaining({ fetch: mockFetch }),
      );
    });
  });

  describe('unsupported model types', () => {
    it('should throw NoSuchModelError for languageModel', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });

      expect(() => provider.languageModel('gpt-4')).toThrow(NoSuchModelError);
    });

    it('should throw NoSuchModelError for embeddingModel', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });

      expect(() => provider.embeddingModel('text-embedding-3-small')).toThrow(
        NoSuchModelError,
      );
    });
  });

  describe('provider metadata', () => {
    it('should have specificationVersion v3', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      expect(provider.specificationVersion).toBe('v3');
    });
  });
});

